What does this program print?

```cpp
#include <iostream>
#include <stdexcept>

int main() {
    try {
        throw std::runtime_error("oops");
        std::cout << "A\n";
    } catch (const std::runtime_error& e) {
        std::cout << "B\n";
    }
    std::cout << "C\n";
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>
#include <stdexcept>

void inner() { throw std::runtime_error("fail"); }
void outer() { inner(); }

int main() {
    try {
        outer();
    } catch (const std::runtime_error& e) {
        std::cout << e.what() << "\n";
    }
    return 0;
}
```

This program is supposed to print `"Caught: bad input"` but instead terminates abnormally. What is wrong?

```cpp
#include <iostream>
#include <stdexcept>

void validate(int x) {
    if (x < 0)
        throw std::invalid_argument("bad input");
}

int main() {
    validate(-1);
    try {
        std::cout << "Caught: bad input\n";
    } catch (const std::invalid_argument& e) {
        std::cout << "Caught: " << e.what() << "\n";
    }
    return 0;
}
```
